@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply

<div class="card">
    <div class="card-header"><h5 class="mb-0">Work History</h5></div>
    <div class="card-body">
        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            <WorkEntryForm
                Entry="Entries[index]"
                Index="index"
                CanRemove="Entries.Count > 1"
                OnChanged="entry => HandleEntryChanged(index, entry)"
                OnRemove="() => HandleRemove(index)" />
        }

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        @if (_showError)
        {
            <div class="alert alert-danger py-2">Each position must have at least a company name and job title.</div>
        }

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-outline-secondary" @onclick="() => OnBack.InvokeAsync()">&larr; Back</button>
            <button type="button" class="btn btn-primary" @onclick="HandleNext">Next &rarr;</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryForm.WorkEntryModel> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryForm.WorkEntryModel>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private bool _showError;

    private void HandleEntryChanged(int index, WorkEntryForm.WorkEntryModel updated)
    {
        Entries[index] = updated;
    }

    private void HandleRemove(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryForm.WorkEntryModel("", "", DateTime.Today, null, "", false));
    }

    private async Task HandleNext()
    {
        _showError = Entries.Any(e => string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title));
        if (_showError) return;
        await OnNext.InvokeAsync(Entries);
    }
}

@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply

<div class="card">
    <div class="card-header"><h5 class="mb-0">References</h5></div>
    <div class="card-body">
        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            <ReferenceForm
                Entry="References[index]"
                Index="index"
                CanRemove="References.Count > 2"
                OnChanged="entry => HandleChanged(index, entry)"
                OnRemove="() => HandleRemove(index)" />
        }

        @if (References.Count < 3)
        {
            <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                + Add Reference
            </button>
        }

        @if (_showError)
        {
            <div class="alert alert-danger py-2">Each reference must have at least a name and email.</div>
        }

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-outline-secondary" @onclick="() => OnBack.InvokeAsync()">&larr; Back</button>
            <button type="button" class="btn btn-primary" @onclick="HandleNext">Next &rarr;</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<ReferenceForm.ReferenceModel> References { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<ReferenceForm.ReferenceModel>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private bool _showError;

    private void HandleChanged(int index, ReferenceForm.ReferenceModel updated)
    {
        References[index] = updated;
    }

    private void HandleRemove(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceForm.ReferenceModel("", "", "", ""));
    }

    private async Task HandleNext()
    {
        _showError = References.Any(r => string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email));
        if (_showError) return;
        await OnNext.InvokeAsync(References);
    }
}

@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply

<div class="card">
    <div class="card-header"><h5 class="mb-0">Cover Letter</h5></div>
    <div class="card-body">
        <div class="mb-3">
            <label for="coverLetter" class="form-label">Write your cover letter</label>
            <textarea id="coverLetter" class="form-control" rows="10" maxlength="@MaxLength" @bind="CoverLetter"></textarea>
            <div class="form-text text-end">@(CoverLetter?.Length ?? 0) / @MaxLength characters</div>
