        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-outline-secondary" @onclick="() => OnBack.InvokeAsync()">&larr; Back</button>
            <button type="button" class="btn btn-primary" @onclick="HandleNext">Next &rarr;</button>
        </div>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync(CoverLetter);
    }
}

@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply

<div class="card">
    <div class="card-header"><h5 class="mb-0">Review &amp; Submit</h5></div>
    <div class="card-body">
        @if (IsSubmitted)
        {
            <div class="alert alert-success text-center py-4">
                <h4>Application Submitted!</h4>
                <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
            </div>
        }
        else
        {
            <!-- Personal Info -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="text-primary">Personal Information</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
                </div>
                <hr class="mt-1" />
                <div class="row">
                    <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                    <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                    <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                    <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
                </div>
            </div>

            <!-- Work History -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="text-primary">Work History</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
                </div>
                <hr class="mt-1" />
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 ps-2 border-start border-3">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") &ndash;
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1 small">@entry.Description</p>
                        }
                    </div>
                }
            </div>

            <!-- References -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="text-primary">References</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
                </div>
                <hr class="mt-1" />
                @foreach (var r in References)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                    </div>
                }
            </div>

            <!-- Cover Letter -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="text-primary">Cover Letter</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
                </div>
                <hr class="mt-1" />
                <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger py-2">@ErrorMessage</div>
            }

            <div class="d-flex justify-content-between">
                <button type="button" class="btn btn-outline-secondary" @onclick="() => OnBack.InvokeAsync()">&larr; Back</button>
                <button type="button" class="btn btn-success btn-lg" @onclick="() => OnSubmit.InvokeAsync()" disabled="@IsSubmitting">
                    @if (IsSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Submit Application
                </button>
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoStep.PersonalInfoResult Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryForm.WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceForm.ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }
    [Parameter] public string? ErrorMessage { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSubmit { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
}

namespace sv_9932c278d672407d96d368d0e4ff91a8.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var isFuture = !isCompleted && !isCurrent;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")">
                @if (isCompleted)
                {
                    <button type="button" class="btn step-circle completed-circle mx-auto" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)" aria-label="Go back to @StepNames[stepIndex]">
                        <span>&#10003;</span>
                    </button>
                }
                else
                {
                    <div class="step-circle @(isCurrent ? "current-circle" : "future-circle") mx-auto">
                        <span>@(stepIndex + 1)</span>
                    </div>
                }
                <div class="step-label mt-1 small">@StepNames[stepIndex]</div>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: 55%;
    width: 90%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    position: relative;
    z-index: 1;
}

.completed-circle {
    background-color: #198754;
    color: white;
    border: none;
    padding: 0;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    cursor: pointer;
}

.completed-circle:hover {
    background-color: #157347;
}

.current-circle {
    background-color: #0d6efd;
    color: white;
    border: 2px solid #0d6efd;
}

.future-circle {
    background-color: #e9ecef;
    color: #6c757d;
    border: 2px solid #dee2e6;
}

.step-label {
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply

<div class="card">
    <div class="card-header"><h5 class="mb-0">Personal Information</h5></div>
    <div class="card-body">
        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
            <input id="fullName" type="text" class="form-control @ValidationClass(nameof(FullName))" @bind="FullName" />
            @if (IsFieldInvalid(nameof(FullName)))
            {
                <div class="invalid-feedback">Full name is required.</div>
            }
        </div>
        <div class="mb-3">
            <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
            <input id="email" type="email" class="form-control @ValidationClass(nameof(Email))" @bind="Email" />
            @if (IsFieldInvalid(nameof(Email)))
            {
                <div class="invalid-feedback">@_emailError</div>
            }
        </div>
        <div class="row">
            <div class="col-md-6 mb-3">
                <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
                <input id="phone" type="tel" class="form-control @ValidationClass(nameof(Phone))" @bind="Phone" />
                @if (IsFieldInvalid(nameof(Phone)))
                {
                    <div class="invalid-feedback">Phone number is required.</div>
                }
            </div>
            <div class="col-md-6 mb-3">
                <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
                <input id="address" type="text" class="form-control @ValidationClass(nameof(Address))" @bind="Address" />
                @if (IsFieldInvalid(nameof(Address)))
                {
                    <div class="invalid-feedback">Address is required.</div>
                }
            </div>
        </div>

        @if (_validating)
        {
            <div class="alert alert-info py-2">Validating email...</div>
        }

        <div class="d-flex justify-content-end">
            <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">Next &rarr;</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<PersonalInfoResult> OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private HashSet<string> _invalidFields = new();
    private string _emailError = "Email is required.";
    private bool _validating;

    public record PersonalInfoResult(string FullName, string Email, string Phone, string Address);

    private bool IsFieldInvalid(string field) => _invalidFields.Contains(field);
    private string ValidationClass(string field) => _invalidFields.Contains(field) ? "is-invalid" : "";

    private async Task HandleNext()
    {
        _invalidFields.Clear();

        if (string.IsNullOrWhiteSpace(FullName)) _invalidFields.Add(nameof(FullName));
        if (string.IsNullOrWhiteSpace(Email))
        {
            _emailError = "Email is required.";
            _invalidFields.Add(nameof(Email));
        }
        if (string.IsNullOrWhiteSpace(Phone)) _invalidFields.Add(nameof(Phone));
        if (string.IsNullOrWhiteSpace(Address)) _invalidFields.Add(nameof(Address));

        if (_invalidFields.Count > 0) return;

        _validating = true;
        StateHasChanged();

        try
        {
            var isValid = await ValidateEmail(Email);
            if (!isValid)
            {
                _emailError = "This email address is not valid.";
                _invalidFields.Add(nameof(Email));
                return;
            }
        }
        finally
        {
            _validating = false;
        }

        await OnNext.InvokeAsync(new PersonalInfoResult(FullName, Email, Phone, Address));
    }
}

@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>
        <div class="row">
            <div class="col-md-6 mb-3">
                <label class="form-label">Company Name</label>
                <input type="text" class="form-control" value="@Entry.Company" @onchange="e => Update(company: (string?)e.Value)" />
            </div>
            <div class="col-md-6 mb-3">
                <label class="form-label">Job Title</label>
                <input type="text" class="form-control" value="@Entry.Title" @onchange="e => Update(title: (string?)e.Value)" />
            </div>
        </div>
        <div class="row">
            <div class="col-md-4 mb-3">
                <label class="form-label">Start Date</label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")" @onchange="e => Update(startDate: DateTime.TryParse((string?)e.Value, out var d) ? d : Entry.StartDate)" />
            </div>
            <div class="col-md-4 mb-3">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@Entry.EndDate?.ToString("yyyy-MM-dd")" disabled="@IsCurrent" @onchange="e => Update(endDate: DateTime.TryParse((string?)e.Value, out var d) ? d : null)" />
            </div>
            <div class="col-md-4 mb-3 d-flex align-items-end">
                <div class="form-check">
                    <input type="checkbox" class="form-check-input" id="current-@Index" checked="@IsCurrent" @onchange="HandleCurrentToggle" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
        </div>
        <div class="mb-0">
            <label class="form-label">Description</label>
            <textarea class="form-control" rows="3" value="@Entry.Description" @onchange="e => Update(description: (string?)e.Value)"></textarea>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryModel> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null && Entry.IsCurrent;

    private void Update(string? company = null, string? title = null, DateTime? startDate = null, DateTime? endDate = null, string? description = null, bool? isCurrent = null)
    {
        var updated = Entry with
        {
            Company = company ?? Entry.Company,
            Title = title ?? Entry.Title,
            StartDate = startDate ?? Entry.StartDate,
            EndDate = isCurrent == true ? null : (endDate ?? Entry.EndDate),
            Description = description ?? Entry.Description,
            IsCurrent = isCurrent ?? Entry.IsCurrent
        };
        OnChanged.InvokeAsync(updated);
    }

    private void HandleCurrentToggle(ChangeEventArgs e)
    {
        var isChecked = (bool)(e.Value ?? false);
        Update(isCurrent: isChecked, endDate: isChecked ? null : Entry.EndDate);
    }

    public record WorkEntryModel(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description, bool IsCurrent);
}

