                </div>
                <hr class="mt-1" />
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 ps-2 border-start border-3">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") &ndash;
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1 small">@entry.Description</p>
                        }
                    </div>
                }
            </div>

            <!-- References -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="text-primary">References</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
                </div>
                <hr class="mt-1" />
                @foreach (var r in References)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                    </div>
                }
            </div>

            <!-- Cover Letter -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="text-primary">Cover Letter</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
                </div>
                <hr class="mt-1" />
                <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger py-2">@ErrorMessage</div>
            }

            <div class="d-flex justify-content-between">
                <button type="button" class="btn btn-outline-secondary" @onclick="() => OnBack.InvokeAsync()">&larr; Back</button>
                <button type="button" class="btn btn-success btn-lg" @onclick="() => OnSubmit.InvokeAsync()" disabled="@IsSubmitting">
                    @if (IsSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Submit Application
                </button>
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoStep.PersonalInfoResult Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryForm.WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceForm.ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }
    [Parameter] public string? ErrorMessage { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSubmit { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
}
"}

