.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: 55%;
    width: 90%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    position: relative;
    z-index: 1;
}

.completed-circle {
    background-color: #198754;
    color: white;
    border: none;
    padding: 0;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    cursor: pointer;
}

.completed-circle:hover {
    background-color: #157347;
}

.current-circle {
    background-color: #0d6efd;
    color: white;
    border: 2px solid #0d6efd;
}

.future-circle {
    background-color: #e9ecef;
    color: #6c757d;
    border: 2px solid #dee2e6;
}

.step-label {
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

