@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>
        <div class="row">
            <div class="col-md-6 mb-3">
                <label class="form-label">Company Name</label>
                <input type="text" class="form-control" value="@Entry.Company" @onchange="e => Update(company: (string?)e.Value)" />
            </div>
            <div class="col-md-6 mb-3">
                <label class="form-label">Job Title</label>
                <input type="text" class="form-control" value="@Entry.Title" @onchange="e => Update(title: (string?)e.Value)" />
            </div>
        </div>
        <div class="row">
            <div class="col-md-4 mb-3">
                <label class="form-label">Start Date</label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")" @onchange="e => Update(startDate: DateTime.TryParse((string?)e.Value, out var d) ? d : Entry.StartDate)" />
            </div>
            <div class="col-md-4 mb-3">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@Entry.EndDate?.ToString("yyyy-MM-dd")" disabled="@IsCurrent" @onchange="e => Update(endDate: DateTime.TryParse((string?)e.Value, out var d) ? d : null)" />
            </div>
            <div class="col-md-4 mb-3 d-flex align-items-end">
                <div class="form-check">
                    <input type="checkbox" class="form-check-input" id="current-@Index" checked="@IsCurrent" @onchange="HandleCurrentToggle" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
        </div>
        <div class="mb-0">
            <label class="form-label">Description</label>
            <textarea class="form-control" rows="3" value="@Entry.Description" @onchange="e => Update(description: (string?)e.Value)"></textarea>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryModel> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null && Entry.IsCurrent;

    private void Update(string? company = null, string? title = null, DateTime? startDate = null, DateTime? endDate = null, string? description = null, bool? isCurrent = null)
    {
        var updated = Entry with
        {
            Company = company ?? Entry.Company,
            Title = title ?? Entry.Title,
            StartDate = startDate ?? Entry.StartDate,
            EndDate = isCurrent == true ? null : (endDate ?? Entry.EndDate),
            Description = description ?? Entry.Description,
            IsCurrent = isCurrent ?? Entry.IsCurrent
        };
        OnChanged.InvokeAsync(updated);
    }

    private void HandleCurrentToggle(ChangeEventArgs e)
    {
        var isChecked = (bool)(e.Value ?? false);
        Update(isCurrent: isChecked, endDate: isChecked ? null : Entry.EndDate);
    }

    public record WorkEntryModel(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description, bool IsCurrent);
}

