namespace sv_9932c278d672407d96d368d0e4ff91a8.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@page "/apply"
@rendermode InteractiveServer
@namespace sv_9932c278d672407d96d368d0e4ff91a8.Components.Pages.Apply
@using sv_9932c278d672407d96d368d0e4ff91a8.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep" CompletedSteps="_completedSteps" OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep
                FullName="@_personal.FullName"
                Email="@_personal.Email"
                Phone="@_personal.Phone"
                Address="@_personal.Address"
                ValidateEmail="ApplicationService.ValidateEmailAsync"
                OnNext="HandlePersonalNext" />
            break;

        case 1:
            <WorkHistoryStep
                Entries="_workEntries"
                OnNext="HandleWorkNext"
                OnBack="GoBack" />
            break;

        case 2:
            <ReferencesStep
                References="_references"
                OnNext="HandleReferencesNext"
                OnBack="GoBack" />
            break;

        case 3:
            <CoverLetterStep
                CoverLetter="@_coverLetter"
                OnNext="HandleCoverLetterNext"
                OnBack="GoBack" />
            break;

        case 4:
            <ReviewStep
                Personal="_personalResult!"
                WorkEntries="_workEntries"
                References="_references"
                CoverLetter="@_coverLetter"
                IsSubmitting="_isSubmitting"
                IsSubmitted="_isSubmitted"
                ApplicationId="_applicationId"
                ErrorMessage="@_submitError"
                OnEditSection="GoToStep"
                OnSubmit="HandleSubmit"
                OnBack="GoBack" />
            break;
    }
</div>

@code {
    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();

    // Step 1 state
    private PersonalInfoStep.PersonalInfoResult _personal = new("", "", "", "");
    private PersonalInfoStep.PersonalInfoResult? _personalResult;

    // Step 2 state
    private List<WorkEntryForm.WorkEntryModel> _workEntries = new()
    {
        new WorkEntryForm.WorkEntryModel("", "", DateTime.Today, null, "", false)
    };

    // Step 3 state
    private List<ReferenceForm.ReferenceModel> _references = new()
    {
        new ReferenceForm.ReferenceModel("", "", "", ""),
        new ReferenceForm.ReferenceModel("", "", "", "")
    };

    // Step 4 state
    private string _coverLetter = "";

    // Step 5 state
    private bool _isSubmitting;
    private bool _isSubmitted;
    private int _applicationId;
    private string? _submitError;

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _currentStep = step;
        }
    }

    private void GoBack()
    {
        if (_currentStep > 0)
            _currentStep--;
    }

    private void AdvanceStep()
    {
        _completedSteps.Add(_currentStep);
        _currentStep++;
    }

    private void HandlePersonalNext(PersonalInfoStep.PersonalInfoResult result)
    {
        _personal = result;
        _personalResult = result;
        AdvanceStep();
    }

    private void HandleWorkNext(List<WorkEntryForm.WorkEntryModel> entries)
    {
        _workEntries = entries;
        AdvanceStep();
    }

    private void HandleReferencesNext(List<ReferenceForm.ReferenceModel> refs)
    {
        _references = refs;
        AdvanceStep();
    }

    private void HandleCoverLetterNext(string coverLetter)
    {
        _coverLetter = coverLetter;
        AdvanceStep();
    }

    private async Task HandleSubmit()
    {
        _isSubmitting = true;
        _submitError = null;
        StateHasChanged();

        try
        {
            var application = new JobApplication(
                new PersonalInfo(_personalResult!.FullName, _personalResult.Email, _personalResult.Phone, _personalResult.Address),
                new WorkHistory(_workEntries.Select(e =>
                    new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
                _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                _coverLetter
            );

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _isSubmitted = true;
            _completedSteps.Add(4);
        }
        catch (Exception ex)
        {
            _submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}

